INSERT INTO transfer_outgoing VALUES(1,'2026-summer',3,'Arsenal','LOW','아스날 관심 있으나 빌라 £60m 요구 vs 아스날 £35m 선. Football Insider: 빌라 구단은 이번 윈도우 어떤 오퍼도 수용할 계획 없음(에메리, 콘사를 핵심 전력으로 판단·CL 복귀 시즌 대비). [2026-07-09 watch: 클럽의 명확한 매각 거부 확인 — MEDIUM-LOW→LOW 하향]','https://www.footballinsider247.com/what-aston-villa-thinks-about-losing-ezri-konsa-to-arsenal/ ; https://readastonvilla.com/2026/07/03/arsenal-konsa-interest-aston-villa-60m-transfer-stance/ (2026-07-09)','LOW — Football Insider(Tier2급): 클럽이 매각 계획 없음을 명시적으로 확인.');
INSERT INTO transfer_outgoing VALUES(2,'2026-summer',13,'Arsenal','HIGH','개인 조건 "매우 매우 가깝다"(FootballTransfers 단독) — 5년 계약 준비, 아스날 컨빈스 단계. 이적료 격차 큼: 빌라 £130m 요구 vs 아스날 €85m(반반 분할지급) 제안. [2026-07-09 watch: 개인조건 진전으로 등급 MEDIUM-HIGH→HIGH 상향, 단 이적료 협상은 미해결]','https://www.footballtransfers.com/en/transfer-news/uk-premier-league/2026/07/exclusive-arsenal-very-close-to-morgan-rogers-transfer-breakthrough ; https://www.teamtalk.com/arsenal/morgan-rogers-transfer-news-record-bid-imminent-from-arsenal-villa (2026-07-09)','HIGH — 아스날 개인조건 임박·완료 예상(로저스 아스날/바이에른만 희망); 이적료 이견(빌라 £130m+ vs 아스날 £85m). 재검증 2026-07-10.');
INSERT INTO transfer_outgoing VALUES(3,'2026-summer',1,'Juventus','HIGH','유벤투스와 개인조건 구두 합의(2029년까지 3년, 연봉 €5.5m — 현재 €7m에서 감액 수용). Fabrizio Romano: 유벤투스 다이렉트 컨택 확인. 이적료 격차: 빌라 최소 €10m 요구 vs 유벤투스 최대 €5m 추가 의향. [2026-07-09 watch: 개인조건 합의로 HIGH 유지·근거 보강, 협상은 월드컵 이후로 지연 전망]','https://www.goal.com/en/lists/emi-martinez-verbally-agrees-juventus-transfer-aston-villa-and-argentina-goalkeeper-prepared-to-reduce-salary/blt15e7adefed63d273 ; https://www.caughtoffside.com/2026/07/08/juventus-direct-contact-emiliano-martinez-fabrizio-romano/ (2026-07-09)','HIGH — 유벤투스와 구두합의(3년 2029), 급여 삭감 수용; 단 이적료 이견(빌라 €10m vs 유베 저가). 빌라는 레스테스 구두합의로 대체 준비. 재검증 2026-07-10.');
INSERT INTO transfer_outgoing VALUES(4,'2026-summer',9,'Fenerbahçe / Al-Ittihad','LOW','사우디 클럽 관심 있으나 선수 본인이 사우디행 의사 없음. 갈라타사라이(튀르키예)도 "기대 중"이라 보도되나 선수는 튀르키예행도 원치 않는다고 과거 발언. 에메리는 오히려 틸레만스 이탈을 막을 계획이며, 자금 필요시 다른 선수를 먼저 매각할 방침. [2026-07-09 watch: 목적지 불일치+에메리의 유지 의사 확인 — MEDIUM→LOW 하향]','https://www.astonvillanews.co.uk/2026/05/26/youri-tielemans-exit-expected-as-aston-villa-line-up-gabriel-sara-deal/ ; https://www.footballinsider247.com/youri-tielemans-unai-emery-puts-new-plan-in-place-to-block-aston-villa-exit/ (2026-07-09)','LOW — Football Insider(Tier2급): 에메리가 이탈 저지 계획, 목적지(사우디/튀르키예) 모두 선수 본인 의사와 불일치.');
INSERT INTO transfer_outgoing VALUES(5,'2026-summer',16,'Fenerbahçe','MEDIUM-HIGH','왓킨스가 페네르바흐체 계약조건에 서명(구조 합의), 이적료만 남은 상태. 이적료 격차: 페네르바흐체 €25m 제안 vs 빌라 €35m 요구. 클럽간 협상은 월드컵 이후로 예정, 왓킨스는 2028년까지 계약 중.','https://www.astonvillanews.co.uk/transfers/why-aston-villa-are-set-for-ollie-watkins-heartbreak-as-fenerbahce-close-in ; https://uk.sports.yahoo.com/news/why-aston-villa-set-ollie-133854669.html (2026-07-09)','MEDIUM-HIGH — 페너바체와 개인조건(3년 €9m) 합의했으나 빌라 매각 거부(계약 2028)+이적료 이견(€35m vs €25m), 본인 WC 집중. 재검증 2026-07-10.');
INSERT INTO transfer_outgoing VALUES(6,'2026-summer',8,'Manchester United(관심, 구체적 딤 확인 안됨)','LOW','오나나 이탈설 자체는 존재(맨유 롱텀 타겟, "월드클래스 클럽" 발언)하나, 2026-07-07 월드컵에서 ACL 부상 확정 — 장기 재활 필요해 이번 윈도우 이적은 현실성 낮음. [2026-07-09: 부상 사실을 근거로 LOW 부여, 부상 이전 루머 기준이면 MEDIUM-HIGH였을 것]','https://www.footballinsider247.com/amadou-onana-closing-in-on-aston-villa-exit-as-big-money-deal-lined-up ; https://en.wikipedia.org/wiki/Amadou_Onana (2026-07-09)','LOW — Football Insider(Tier2급) 보도는 부상 이전 시점으로 추정, ACL 부상으로 실현 가능성 낮음.');
INSERT INTO transfer_outgoing VALUES(7,'2026-summer',11,'Brighton / Sunderland','MEDIUM-LOW','브라이튼(작년 12월부터 모니터링)·선덜랜드("구체적 관심", 더치 매체 Voetbal International)가 관심 표명하나 공식 오퍼 없음. 빌라는 오히려 신계약 협상 중이며 에메리가 잔류를 원한다고 확인.','https://readastonvilla.com/2026/06/08/aston-villa-lamare-bogarde-contract-brighton-transfer-2026/ ; https://www.footballinsider247.com/aston-villa-open-lamare-bogarde-contract-talks-as-transfer-interest-grows-in-midfielder/ (2026-07-09)','MEDIUM-LOW — Football Insider(Tier2급): 관심 확인되나 공식 오퍼 없음, 클럽은 재계약으로 잔류 유도 중.');
